+      path: `agents.defaults.sandbox.ssh.${key}`,
+      expected: "string",
+      defaults: params.defaults,
+      context: params.context,
+      active: defaultsActive || inheritedDefaultsUsage[key],
+      inactiveReason: "sandbox SSH backend is not active.",
+      apply: (value) => {
+        defaultsSsh[key] = value;
+      },
+    });
+  }
+}
